CREATE TABLE fiscal.recurring_agreements(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,branch_id uuid NOT NULL,counterparty_ref text NOT NULL,counterparty_name text NOT NULL,description text NOT NULL,amount bigint NOT NULL CHECK(amount>0),day_of_month integer NOT NULL CHECK(day_of_month BETWEEN 1 AND 28),next_run_on date NOT NULL,active boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,counterparty_ref,description));
CREATE TABLE fiscal.recurring_executions(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id uuid NOT NULL,agreement_id uuid NOT NULL REFERENCES fiscal.recurring_agreements(id),scheduled_on date NOT NULL,commercial_document_id uuid NOT NULL REFERENCES fiscal.commercial_documents(id),created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,agreement_id,scheduled_on));
ALTER TABLE fiscal.recurring_agreements ENABLE ROW LEVEL SECURITY;ALTER TABLE fiscal.recurring_executions ENABLE ROW LEVEL SECURITY;REVOKE ALL ON fiscal.recurring_agreements,fiscal.recurring_executions FROM anon,authenticated;
